sEnvironment = Upper(Trim(pEnvironment));
sAction = Trim(pAction);
sObjectType = Trim(pObjectType);
sObjectName = Trim(pObjectName);
sStatus = Upper(Trim(pStatus));
sMessage = Trim(pMessage);
sLogToCube = Upper(Trim(pLogToCube));
sLogFile = Trim(pLogFile);
If(sStatus @= ''); sStatus = 'INFO'; EndIf;
If(sLogToCube @= ''); sLogToCube = 'Y'; EndIf;
If(sLogFile @= ''); sLogFile = 'docs/security/IMF_Security_Bootstrap.log'; EndIf;
sLogLine = '[IMF_SECURITY][' | sEnvironment | '][' | sStatus | '][' | sAction | '][' | sObjectType | '][' | sObjectName | '] ' | sMessage;
If(sLogToCube @= 'Y');
  # TODO: Write to IMF.C.EventLog once the cube grain and insertion convention are finalized.
EndIf;
ASCIIOutput(sLogFile, sLogLine);
LogOutput('INFO', sLogLine);

